B.ail=new A.c("With N-2e, Black begins to attack the 1st file. If White plays S-2d after Black's P-1d, there will follow: P-2e, Sx2e, P-1c+, good for Black. So White has to play Sx1d. Then after Lx1d, Lx1d, Rx1d, White drops a Lance on 1a, which looks quite promising on White's part.")
B.a2V=A.a(s(["P*1c","Lx1c","Bx1c+","Nx1c","L*3i"]),t.s)
B.aaS=new A.O(null,B.a2V,B.l)
