B.ajK=new A.c("The last move in the above diagram, L*3i, is what you should remember, the latest joseki. Drop the Lance from the bottom. Now the third file is the target.")
B.a2v=A.a(s(["N-7c","P-3e","Px3e","L*3d","N*3c","Lx3e"]),t.s)
B.aac=new A.O(null,B.a2v,B.u)
