B.apq=new A.bg(7,B.aN,"Save the Gold till the end (for the coup de grace)","Kin wa todome ni nokose",B.ZK)
B.amD=new A.c("A Gold can move diagonally forward, but needs two moves to get back to where it was.")
B.Ms=new A.p("7nl/3R+P1gk1/5gspp/5pp2/9/9/9/9/9 b 2P","Diagram 1")
