B.N8=new A.p("ln1g1k1nl/1r3sg2/p2psp1pp/1pp3p2/4b4/2PP5/PPSG1PPPP/1BG2S1R1/LN2K2NL b pP","Diagram 1-1")
B.an2=new A.c("Diagram 1-1 is from a Yagura opening where White has just exchanged Pawns on 5e.")
B.ag3=new A.c("Here White has, roughly speaking, two ways to deploy his pieces, depending on where the Bishop is placed.")
B.a1x=A.a(s(["K-6i","S-5d","P-2f","B-2b","P-2e","P-6d"]),t.s)
B.a9H=new A.O("Plan A:",B.a1x,B.l)
B.aki=new A.c("Plan A aims at attacking the King's head directly, with the Bishop back on 2b.")
