B.aag=new A.O("Moves from Diagram 2-2:",B.a2U,B.l)
B.ai4=new A.c("B*7g is the move to play here. Black takes a Bishop in exchange for a Rook, which is not a material loss. After White's S-2b, there is a very good move on Black's part, which is...?")
B.a1s=A.a(s(["B*6e"]),t.s)
B.aaq=new A.O(null,B.a1s,B.l)
