B.aaN=new A.O(null,B.Vd,B.u)
B.NN=new A.p("ln1g1k1nl/4r2g1/p1pp1s1p1/8p/4pNp2/P1P4RP/1P1P5/2KGSG3/LN6L w BS3Pbs3p","Diagram 3")
B.ag6=new A.c("The series of moves above leaves White's camp in a complete mess with most of the pieces disconnected with each other, while Black has at least two possibilities to play: S*5c and R6f. Either looks good.")
B.ahb=new A.c("Diagram 3 clearly shows Black is dominant at this point.")
B.a01=A.a(s([B.agm,B.aeZ,B.MQ,B.aj8,B.ab_,B.anB,B.a8Z,B.NF,B.agH,B.aaN,B.NN,B.ag6,B.ahb]),t.A)
B.adV=new A.aq(B.a01)
B.a0m=A.a(s([B.adV]),t.l)
B.apl=new A.bg(26,B.bD,"The 5e Vanguard Pawn is the Tennozan Mountain","Go-go no kurai wa Tennozan",B.a0m)
B.am_=new A.c("The 5e vanguard Pawn is no longer a game-deciding tactic in present-day shogi. Instead, we see 4e as a square to hold.")
B.M7=new A.p("ln3gbnl/1r2g1s2/p2p1psk1/2p1p1ppp/1p1P1P3/2P1S1PPP/PPB1P1N2/3RG1S2/LN3GK1L w -","Diagram 1")
B.aes=new A.c("White in Diagram 1 (last move P6e) has started to assume a left-Mino castle, but has been unable to build it into the ultimate left-Mino, which is completed with the Pawn on 4d and the Gold on 4c. Not only has Black's vanguard Pawn on 4e prevented White's ideal formation, the Bishop on 8h is now a direct threat for White's camp because of the kurai.")
B.aim=new A.c("Even if White plays G5c and then P4d, in an attempt to make it into a better-shaped castle, there will follow: Px4d, Gx4d, P*4e, G4c. He will end up having a defect on 4d: Black will be able to drop any acquired piece on 4d.")
B.aiP=new A.c("The 4e vanguard Pawn has been proved to be the real Tennozan, which explains the recent sharp decline of the left-Mino opening games among professionals.")
B.O1=new A.p("l6nl/1r3bgk1/p1ns1gspp/2ppppp2/1p3P1P1/2PPP1P2/PPSG1SN1P/1KGB3R1/LN6L w -","Diagram 2")
B.ahC=new A.c("Diagram 2 shows a double fortress opening, where Black has just played P4e. White should play Px4e here. Supposing he plays 8a instead, which happens to be a bad move, how should Black take advantage of that?")
B.a51=A.a(s(["R8a","Px4d","Gx4d","P*4e","G4d-4c","B4f"]),t.s)
B.aaK=new A.O("Moves after Diagram 2:",B.a51,B.u)
