B.a3G=A.a(s([B.acI]),t.l)
B.apn=new A.bg(42,B.cH,"Drop a Silver behind the King","Gyoku no shita kara Gin wo ute",B.a3G)
B.amv=new A.c("How many pieces will you need to continue attacking till the end of the game? Three is not always enough. When you have four attacking pieces including those in hand, your offensive will be strong enough to carry through.")
