B.aek=new A.c("In Diagram 3, the position is clearly in Black's favor.")
B.ahA=new A.c("When you approach the King, try to procure four attacking pieces. Then you won't have to worry about running out of steam.")
B.Xv=A.a(s([B.amv,B.ahp,B.Pf,B.am1,B.aat,B.O6,B.ab3,B.Ok,B.aek,B.ahA]),t.A)
